{
  "name": "SRD Closer - VAPI → Kommo → WhatsApp Automático",
  "nodes": [
    {
      "parameters": {},
      "name": "Start",
      "type": "n8n-nodes-base.start",
      "typeVersion": 1,
      "position": [50, 300]
    },
    {
      "parameters": {
        "resource": "message",
        "operation": "sendText",
        "number": "{{ $json.body.phoneNumber }}",
        "text": "Olá {{ $json.body.customerName }}! Tudo bem? Recebi seu cadastro. Você trabalha com educação?"
      },
      "name": "VAPI Call Trigger",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 1,
      "position": [200, 300]
    },
    {
      "parameters": {
        "url": "=https://api.vapi.ai/call",
        "method": "POST",
        "headers": {
          "Authorization": "Bearer {{ $env.VAPI_API_KEY }}"
        },
        "requestBody": "json",
        "jsonBody": {
          "assistantId": "{{ $env.VAPI_ASSISTANT_ID }}",
          "phoneNumber": "{{ $json.phoneNumber }}",
          "customerName": "{{ $json.customerName }}",
          "metadata": {
            "nicho": "{{ $json.nicho }}",
            "email": "{{ $json.email }}"
          }
        }
      },
      "name": "Disparar Ligação VAPI",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [400, 300]
    },
    {
      "parameters": {
        "url": "={{ $env.KOMMO_DOMAIN }}/api/v4/leads",
        "method": "POST",
        "headers": {
          "Authorization": "Bearer {{ $env.KOMMO_API_KEY }}"
        },
        "requestBody": "json",
        "jsonBody": {
          "name": "{{ $json.customerName }}",
          "phone": "{{ $json.phoneNumber }}",
          "email": "{{ $json.email }}",
          "custom_fields": {
            "nicho": "{{ $json.nicho }}",
            "vapi_call_id": "{{ $json.body.id }}",
            "status_ligacao": "disparada",
            "timestamp": "{{ now() }}"
          }
        }
      },
      "name": "Enviar para Kommo",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [600, 300]
    },
    {
      "parameters": {
        "conditions": {
          "boolean": [
            {
              "value1": "{{ $json.body.endedReason }}",
              "operation": "equals",
              "value2": "hangup"
            }
          ]
        }
      },
      "name": "Qualificou?",
      "type": "n8n-nodes-base.if",
      "typeVersion": 1,
      "position": [800, 300]
    },
    {
      "parameters": {
        "url": "=https://api.evolutionapi.com/api/v1/message/sendText/{{ $env.EVOLUTION_INSTANCE }}",
        "method": "POST",
        "headers": {
          "apikey": "{{ $env.EVOLUTION_API_KEY }}"
        },
        "requestBody": "json",
        "jsonBody": {
          "number": "{{ $json.phoneNumber }}",
          "text": "Olá {{ $json.customerName }}! 👋\n\nThanks pela conversa! Aqui está nosso demo:\n{{ $env.CALENDLY_URL }}\n\nAbraço, SRD Closer Team"
        }
      },
      "name": "Enviar WhatsApp Follow-up",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1000, 200]
    },
    {
      "parameters": {
        "url": "={{ $env.KOMMO_DOMAIN }}/api/v4/leads",
        "method": "PUT",
        "headers": {
          "Authorization": "Bearer {{ $env.KOMMO_API_KEY }}"
        },
        "requestBody": "json",
        "jsonBody": {
          "id": "{{ $json.kommo_lead_id }}",
          "custom_fields": {
            "whatsapp_enviado": "true",
            "status_ligacao": "qualificado_com_whatsapp"
          }
        }
      },
      "name": "Atualizar Status Kommo",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1200, 200]
    },
    {
      "parameters": {
        "action": "append",
        "columns": "Nome,Telefone,Email,Nicho,Status,Data",
        "dataInColumnsFormat": "defineBelow",
        "fieldsUi": {
          "values": [
            {
              "column": "Nome",
              "fieldValue": "{{ $json.customerName }}"
            },
            {
              "column": "Telefone",
              "fieldValue": "{{ $json.phoneNumber }}"
            },
            {
              "column": "Email",
              "fieldValue": "{{ $json.email }}"
            },
            {
              "column": "Nicho",
              "fieldValue": "{{ $json.nicho }}"
            },
            {
              "column": "Status",
              "fieldValue": "qualificado"
            },
            {
              "column": "Data",
              "fieldValue": "{{ now() }}"
            }
          ]
        }
      },
      "name": "Adicionar em Google Sheets",
      "type": "n8n-nodes-base.googleSheets",
      "typeVersion": 2,
      "position": [1400, 200]
    }
  ],
  "connections": {
    "Start": {
      "main": [
        [
          {
            "node": "Disparar Ligação VAPI",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Disparar Ligação VAPI": {
      "main": [
        [
          {
            "node": "Enviar para Kommo",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Enviar para Kommo": {
      "main": [
        [
          {
            "node": "Qualificou?",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Qualificou?": {
      "main": [
        [
          {
            "node": "Enviar WhatsApp Follow-up",
            "type": "main",
            "index": 0
          }
        ],
        []
      ]
    },
    "Enviar WhatsApp Follow-up": {
      "main": [
        [
          {
            "node": "Atualizar Status Kommo",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Atualizar Status Kommo": {
      "main": [
        [
          {
            "node": "Adicionar em Google Sheets",
            "type": "main",
            "index": 0
          }
        ]
      ]
    }
  }
}

